SELECT category
FROM fund_balances
WHERE initial_balance = '1.0';

SELECT category_name, description
FROM budget_categories
WHERE category_id = 1;

SELECT SUM(budget_amount) AS total_budget
FROM budget_plans
WHERE year = 2021 AND status = 'approved';

SELECT MAX(budget_amount) AS max_budget_2021
  FROM budget_plans
  WHERE year = 2021;
